mapper.select:
SELECT p.id, p.position_code as positionCode, p.position_name as positionName, p.org_id as orgId, p.dept_id as deptId, p.position_category as positionCategory, p.rank_grade as rankGrade, p.rank_series as rankSeries, p.job_description as jobDescription, p.requirements, p.status, p.sort_order as sortOrder, p.ext_json as extJson, p.created_by as createdBy, p.created_time as createdTime, p.updated_by as updatedBy, p.updated_time as updatedTime, p.deleted FROM hr_position p WHERE p.deleted = 0
AND p.position_name LIKE CONCAT('%', #{positionName}, '%')
AND p.position_code LIKE CONCAT('%', #{positionCode}, '%')
AND p.org_id = #{orgId}
AND p.dept_id = #{deptId}
AND p.status = #{status}
ORDER BY p.sort_order ASC, p.created_time DESC
